// Simulated generated stub (in reality: from protoc):
interface TradeServiceBlockingStub {
    TradeResponse placeOrder(TradeRequest req);
}
record TradeRequest(String symbol, int qty, String type) {}
record TradeResponse(String orderId, String status) {}

@Service
class TradeClientService {
    // @GrpcClient: real annotation from net.devh starter
    // Injected by Spring gRPC starter from grpc.client.zerodha-trade config:
    // @GrpcClient("zerodha-trade")
    // private ZerodhaTradeServiceGrpc.ZerodhaTradeServiceBlockingStub stub;

    // For testability without gRPC server, use a simulated stub:
    private TradeServiceBlockingStub stub;

    TradeClientService(TradeServiceBlockingStub stub) { this.stub = stub; }

    public String placeOrder(String symbol, int qty, String orderType) {
        try {
            TradeRequest req = new TradeRequest(symbol, qty, orderType);
            TradeResponse response = stub.placeOrder(req);
            return response.orderId();
        } catch (StatusRuntimeException e) {
            // gRPC status codes:
            // UNAVAILABLE: server down
            // DEADLINE_EXCEEDED: timeout
            // PERMISSION_DENIED: auth failed
            // NOT_FOUND: resource doesn't exist
            if (e.getStatus().getCode() == Status.Code.DEADLINE_EXCEEDED) {
                throw new RuntimeException("Trade service timeout", e);
            }
            if (e.getStatus().getCode() == Status.Code.UNAVAILABLE) {
                throw new RuntimeException("Trade service unavailable", e);
            }
            throw new RuntimeException("Trade failed: " + e.getStatus().getDescription(), e);
        }
    }
}

@SpringBootTest
class GrpcClientTest {
    @Test void client_callsStub() {
        // Mock stub:
        TradeServiceBlockingStub mockStub = req -> new TradeResponse("ORD-" + req.symbol(), "PLACED");
        TradeClientService client = new TradeClientService(mockStub);
        String orderId = client.placeOrder("RELIANCE", 10, "BUY");
        assertEquals("ORD-RELIANCE", orderId);
    }
    @Test void statusRuntimeException_handled() {
        // Stub throws UNAVAILABLE:
        TradeServiceBlockingStub failingStub = req -> {
            throw new StatusRuntimeException(Status.UNAVAILABLE.withDescription("server down"));
        };
        TradeClientService client = new TradeClientService(failingStub);
        assertThrows(RuntimeException.class, () -> client.placeOrder("TCS", 5, "SELL"));
    }
}

import io.grpc.*;
import io.grpc.stub.StreamObserver;
import net.devh.boot.grpc.server.service.GrpcService;
import org.springframework.boot.test.context.SpringBootTest;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;

// Simulated proto types:
record PayReq(String merchantId, long amountPaise, String gateway) {}
record PayRes(String paymentId, String status) {}

@GrpcService
class PaymentValidatingGrpcService {
    private final Map<String, PayRes> payments = new HashMap<>();

    // Unary RPC: validates and processes payment
    public void processPayment(PayReq req, StreamObserver<PayRes> obs) {
        // Validate:
        if (req.merchantId() == null || req.merchantId().isBlank()) {
            obs.onError(Status.INVALID_ARGUMENT
                .withDescription("merchantId is required")
                .asRuntimeException()); // gRPC equivalent of 400 Bad Request
            return;
        }
        if (req.amountPaise() <= 0) {
            obs.onError(Status.INVALID_ARGUMENT
                .withDescription("amount must be positive, got: " + req.amountPaise())
                .asRuntimeException());
            return;
        }
        if (!Set.of("HDFC","VISA","RUPAY").contains(req.gateway())) {
            obs.onError(Status.INVALID_ARGUMENT
                .withDescription("unknown gateway: " + req.gateway())
                .asRuntimeException());
            return;
        }

        // Process:
        String paymentId = "PAY-" + System.nanoTime();
        PayRes response = new PayRes(paymentId, "CAPTURED");
        payments.put(paymentId, response);

        obs.onNext(response);
        obs.onCompleted();
    }

    // gRPC Status → HTTP mapping:
    // INVALID_ARGUMENT → 400, NOT_FOUND → 404, UNAUTHENTICATED → 401
    // PERMISSION_DENIED → 403, INTERNAL → 500, UNAVAILABLE → 503
    public void getPayment(String paymentId, StreamObserver<PayRes> obs) {
        PayRes payment = payments.get(paymentId);
        if (payment == null) {
            obs.onError(Status.NOT_FOUND
                .withDescription("payment not found: " + paymentId)
                .asRuntimeException());
            return;
        }
        obs.onNext(payment);
        obs.onCompleted();
    }
}

// Test helper: capture results from StreamObserver:
class TestObserver<T> implements StreamObserver<T> {
    T value; Throwable error; boolean completed;
    @Override public void onNext(T v) { value = v; }
    @Override public void onError(Throwable t) { error = t; }
    @Override public void onCompleted() { completed = true; }
}

@SpringBootTest
class GrpcErrorTest {
    PaymentValidatingGrpcService svc = new PaymentValidatingGrpcService();

    @Test void validRequest_succeeds() {
        TestObserver<PayRes> obs = new TestObserver<>();
        svc.processPayment(new PayReq("MRC-001", 50000L, "HDFC"), obs);
        assertNotNull(obs.value);
        assertEquals("CAPTURED", obs.value.status());
        assertTrue(obs.completed);
        assertNull(obs.error);
    }
    @Test void blankMerchantId_throwsInvalidArgument() {
        TestObserver<PayRes> obs = new TestObserver<>();
        svc.processPayment(new PayReq("", 50000L, "HDFC"), obs);
        assertNull(obs.value);
        assertNotNull(obs.error);
        StatusRuntimeException ex = (StatusRuntimeException) obs.error;
        assertEquals(Status.Code.INVALID_ARGUMENT, ex.getStatus().getCode());
        assertTrue(ex.getStatus().getDescription().contains("merchantId"));
    }
}

import io.grpc.*;
import net.devh.boot.grpc.server.interceptor.GrpcGlobalServerInterceptor;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import java.util.concurrent.atomic.AtomicInteger;

@GrpcGlobalServerInterceptor
class LoggingServerInterceptor implements ServerInterceptor {
    private static final Logger log = LoggerFactory.getLogger(LoggingServerInterceptor.class);
    private final AtomicInteger callCount = new AtomicInteger(0);

    @Override
    public <Req, Resp> ServerCall.Listener<Req> interceptCall(
            ServerCall<Req, Resp> call,
            Metadata headers,
            ServerCallHandler<Req, Resp> next) {

        String methodName = call.getMethodDescriptor().getFullMethodName();
        long startTime = System.currentTimeMillis();
        callCount.incrementAndGet();

        log.info("[gRPC] START: {}", methodName);

        // Wrap the call to intercept completion:
        ServerCall<Req, Resp> wrappedCall = new ForwardingServerCall.SimpleForwardingServerCall<>(call) {
            @Override
            public void close(Status status, Metadata trailers) {
                long latencyMs = System.currentTimeMillis() - startTime;
                log.info("[gRPC] END: {} status={} latency={}ms",
                    methodName, status.getCode(), latencyMs);
                super.close(status, trailers);
            }
        };

        return next.startCall(wrappedCall, headers);
    }

    public int getCallCount() { return callCount.get(); }
}

@SpringBootTest
class GrpcInterceptorTest {
    @Autowired LoggingServerInterceptor interceptor;

    @Test void interceptor_isRegistered() {
        assertNotNull(interceptor);
        // @GrpcGlobalServerInterceptor: auto-registered with all gRPC services
    }
    @Test void interceptor_countsZeroAtStart() {
        // callCount increments on each intercepted call:
        int count = interceptor.getCallCount();
        assertTrue(count >= 0); // 0 if no calls yet
    }
}

import io.grpc.*;
import net.devh.boot.grpc.server.interceptor.GrpcGlobalServerInterceptor;
