import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

// Metadata keys:
class GrpcMetadataKeys {
    static final Metadata.Key<String> MERCHANT_ID =
        Metadata.Key.of("x-merchant-id", Metadata.ASCII_STRING_MARSHALLER);
    static final Metadata.Key<String> AUTH_TOKEN =
        Metadata.Key.of("authorization", Metadata.ASCII_STRING_MARSHALLER);
    static final Metadata.Key<String> TRACE_ID =
        Metadata.Key.of("x-trace-id", Metadata.ASCII_STRING_MARSHALLER);
}

// Server interceptor: extract merchant ID from metadata
@GrpcGlobalServerInterceptor
class MerchantContextInterceptor implements ServerInterceptor {
    private static final Context.Key<String> MERCHANT_CTX = Context.key("merchantId");

    @Override
    public <Req, Resp> ServerCall.Listener<Req> interceptCall(
            ServerCall<Req, Resp> call, Metadata headers, ServerCallHandler<Req, Resp> next) {
        String merchantId = headers.get(GrpcMetadataKeys.MERCHANT_ID);
        // Attach to gRPC Context so service method can access it:
        Context ctx = Context.current().withValue(MERCHANT_CTX,
            merchantId != null ? merchantId : "UNKNOWN");
        return Contexts.interceptCall(ctx, call, headers, next);
    }

    public static String getMerchantId() {
        return MERCHANT_CTX.get(Context.current());
    }
}

// Client interceptor: add auth token to outgoing calls
class AuthTokenClientInterceptor implements ClientInterceptor {
    private final String token;
    AuthTokenClientInterceptor(String token) { this.token = token; }

    @Override
    public <Req, Resp> ClientCall<Req, Resp> interceptCall(
            MethodDescriptor<Req, Resp> method, CallOptions options, Channel next) {
        return new ForwardingClientCall.SimpleForwardingClientCall<>(next.newCall(method, options)) {
            @Override
            public void start(Listener<Resp> responseListener, Metadata headers) {
                headers.put(GrpcMetadataKeys.AUTH_TOKEN, "Bearer " + token);
                super.start(responseListener, headers);
            }
        };
    }
}

@SpringBootTest
class GrpcMetadataTest {
    @Test void metadata_key_definition() {
        // Metadata keys are case-insensitive string keys (ASCII):
        assertNotNull(GrpcMetadataKeys.MERCHANT_ID);
        assertEquals("x-merchant-id", GrpcMetadataKeys.MERCHANT_ID.name());
    }
    @Test void metadata_getValue() {
        Metadata headers = new Metadata();
        headers.put(GrpcMetadataKeys.MERCHANT_ID, "MRC-001");
        assertEquals("MRC-001", headers.get(GrpcMetadataKeys.MERCHANT_ID));
    }
}

import org.springframework.stereotype.*;
import io.grpc.health.v1.HealthCheckResponse;
import org.springframework.boot.actuate.health.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

@Service
class GrpcHealthService {
    // Per-service health status:
    private final Map<String, HealthCheckResponse.ServingStatus> statuses =
        new ConcurrentHashMap<>();

    GrpcHealthService() {
        // Register known services as SERVING on startup:
        setServing("payment-service");
        setServing("trade-service");
    }

    public void setServing(String service) {
        statuses.put(service, HealthCheckResponse.ServingStatus.SERVING);
    }

    public void setNotServing(String service) {
        statuses.put(service, HealthCheckResponse.ServingStatus.NOT_SERVING);
    }

    public HealthCheckResponse.ServingStatus getStatus(String service) {
        return statuses.getOrDefault(service,
            HealthCheckResponse.ServingStatus.SERVICE_UNKNOWN);
    }

    public boolean isAllServing() {
        return statuses.values().stream()
            .allMatch(s -> s == HealthCheckResponse.ServingStatus.SERVING);
    }
}

// Spring Actuator health indicator for gRPC:
@Component
class GrpcHealthIndicator implements HealthIndicator {
    private final GrpcHealthService grpcHealth;
    GrpcHealthIndicator(GrpcHealthService s) { grpcHealth = s; }

    @Override
    public Health health() {
        if (grpcHealth.isAllServing()) {
            return Health.up()
                .withDetail("grpc.payment-service", "SERVING")
                .withDetail("grpc.trade-service", "SERVING")
                .build();
        }
        return Health.down()
            .withDetail("grpc", "One or more gRPC services not serving")
            .build();
    }
}

@SpringBootTest
class GrpcHealthTest {
    @Autowired GrpcHealthService healthSvc;
    @Autowired GrpcHealthIndicator healthIndicator;

    @Test void initialState_allServing() {
        assertEquals(HealthCheckResponse.ServingStatus.SERVING,
            healthSvc.getStatus("payment-service"));
        assertTrue(healthSvc.isAllServing());
    }
    @Test void actuator_reportsUp() {
        Health h = healthIndicator.health();
        assertEquals(Status.UP, h.getStatus());
        assertTrue(h.getDetails().containsKey("grpc.payment-service"));
    }
}

