import io.grpc.*;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicInteger;

interface TradeStub { String execute(String symbol); }

@Service
class DeadlineGrpcClient {
    private final TradeStub stub;
    DeadlineGrpcClient(TradeStub s) { stub = s; }

    public String callWithDeadlineAndRetry(String symbol) {
        try {
            return stub.execute(symbol); // First attempt
        } catch (StatusRuntimeException e) {
            if (e.getStatus().getCode() == Status.Code.DEADLINE_EXCEEDED) {
                // Retry once on timeout (transient issue):
                try {
                    return stub.execute(symbol + "-retry");
                } catch (StatusRuntimeException retryEx) {
                    throw new RuntimeException("Retry also failed: " + retryEx.getStatus(), retryEx);
                }
            }
            if (e.getStatus().getCode() == Status.Code.UNAVAILABLE) {
                // Don't retry unavailable: server is down, retry will also fail
                throw new RuntimeException("Service unavailable, not retrying", e);
            }
            throw new RuntimeException("gRPC error: " + e.getStatus(), e);
        }
    }
}

@SpringBootTest
class DeadlineClientTest {
    @Test void success_returnsResult() {
        TradeStub okStub = symbol -> "ORD-" + symbol;
        DeadlineGrpcClient client = new DeadlineGrpcClient(okStub);
        assertEquals("ORD-RELIANCE", client.callWithDeadlineAndRetry("RELIANCE"));
    }
    @Test void deadlineExceeded_retries() {
        AtomicInteger callCount = new AtomicInteger();
        TradeStub timeoutThenOk = symbol -> {
            if (callCount.incrementAndGet() == 1)
                throw new StatusRuntimeException(Status.DEADLINE_EXCEEDED);
            return "ORD-RETRY-" + symbol;
        };
        DeadlineGrpcClient client = new DeadlineGrpcClient(timeoutThenOk);
        String result = client.callWithDeadlineAndRetry("TCS");
        assertTrue(result.contains("RETRY"));
        assertEquals(2, callCount.get()); // called twice
    }
    @Test void unavailable_throwsImmediately() {
        TradeStub downStub = s -> { throw new StatusRuntimeException(Status.UNAVAILABLE); };
        DeadlineGrpcClient client = new DeadlineGrpcClient(downStub);
        RuntimeException ex = assertThrows(RuntimeException.class,
            () -> client.callWithDeadlineAndRetry("INFY"));
        assertTrue(ex.getMessage().contains("unavailable") || ex.getMessage().contains("not retrying"));
    }
}

