@GrpcGlobalServerInterceptor
class RzpMethodLogger implements ServerInterceptor {
    final Map<String,AtomicInteger> counts = new ConcurrentHashMap<>();
    @Override public <Q,R> ServerCall.Listener<Q> interceptCall(ServerCall<Q,R> call, Metadata h, ServerCallHandler<Q,R> next) {
        counts.computeIfAbsent(call.getMethodDescriptor().getBareMethodName(), k->new AtomicInteger()).incrementAndGet();
        return next.startCall(call, h);
    }
    int count(String method) { return counts.getOrDefault(method, new AtomicInteger()).get(); }
}

@GrpcService
class RazorpayPaymentGrpcSvc {
