    RazorpayPaymentGrpcSvc(RzpPaymentStore s) { store=s; }

    public void processPayment(RzpPayReq req, StreamObserver<RzpPayRes> obs) {
        if (req.amountPaise() <= 0) {
            obs.onError(Status.INVALID_ARGUMENT.withDescription("amount must be positive").asRuntimeException()); return;
        }
        RzpPayRes res = store.save(req);
        obs.onNext(res); obs.onCompleted();
    }
    public void getPaymentStatus(RzpStatusReq req, StreamObserver<RzpPayRes> obs) {
        store.find(req.paymentId()).ifPresentOrElse(
            p -> { obs.onNext(p); obs.onCompleted(); },
            () -> obs.onError(Status.NOT_FOUND.withDescription(req.paymentId()).asRuntimeException()));
    }
    public void cancelPayment(RzpCancelReq req, StreamObserver<RzpPayRes> obs) {
        Optional<RzpPayRes> payment = store.find(req.paymentId());
        if (payment.isEmpty()) { obs.onError(Status.NOT_FOUND.withDescription(req.paymentId()).asRuntimeException()); return; }
        if ("SETTLED".equals(payment.get().status())) {
            obs.onError(Status.FAILED_PRECONDITION.withDescription("Already settled: " + req.paymentId()).asRuntimeException()); return;
        }
        store.updateStatus(req.paymentId(), "CANCELLED");
        obs.onNext(store.find(req.paymentId()).get()); obs.onCompleted();
    }
}

