import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicInteger;

// gRPC load balancing config (application.yml):
// grpc:
//   client:
//     trade-service:
//       # Static multi-address: round-robin across 3 pods
//       address: static://pod-1:9090,pod-2:9090,pod-3:9090
//       default-load-balancing-policy: round_robin
//       negotiation-type: plaintext
//     # OR: Kubernetes service (k8s-aware load balancing):
//     trade-service-k8s:
//       address: dns:///trade-service.zerodha.svc.cluster.local:9090
//       default-load-balancing-policy: round_robin

@Service
class TrafficDistributor {
    private final List<String> pods;
    private final AtomicInteger index = new AtomicInteger(0);
    private final Map<String, Integer> hitCounts = new ConcurrentHashMap<>();
    private final Set<String> unhealthyPods = new HashSet<>();

    TrafficDistributor(List<String> pods) {
        this.pods = new ArrayList<>(pods);
        pods.forEach(p -> hitCounts.put(p, 0));
    }

    // Round-robin: skip unhealthy pods
    public String selectPod() {
        List<String> healthy = pods.stream()
            .filter(p -> !unhealthyPods.contains(p))
            .toList();
        if (healthy.isEmpty()) throw new RuntimeException("All pods unhealthy");

        String pod = healthy.get(index.getAndIncrement() % healthy.size());
        hitCounts.merge(pod, 1, Integer::sum);
        return pod;
    }

    public void markUnhealthy(String pod) { unhealthyPods.add(pod); }
    public Map<String, Integer> getHitCounts() { return Collections.unmodifiableMap(hitCounts); }
}

@SpringBootTest
class GrpcLBTest {
    @Test void roundRobin_distributesEvenly() {
        TrafficDistributor dist = new TrafficDistributor(List.of("pod-1","pod-2","pod-3"));
        // Send 9 requests: expect 3 per pod:
        for (int i = 0; i < 9; i++) dist.selectPod();
        Map<String,Integer> counts = dist.getHitCounts();
        assertEquals(3, counts.get("pod-1"));
        assertEquals(3, counts.get("pod-2"));
        assertEquals(3, counts.get("pod-3"));
    }
    @Test void unhealthyPod_excluded() {
        TrafficDistributor dist = new TrafficDistributor(List.of("pod-1","pod-2","pod-3"));
        dist.markUnhealthy("pod-2");
        for (int i = 0; i < 6; i++) dist.selectPod();
        assertEquals(0, dist.getHitCounts().get("pod-2")); // pod-2 never hit
        assertTrue(dist.getHitCounts().get("pod-1") > 0);
    }
}

