record SynthPayReq(String merchantId, long amount, String gateway) {}
record SynthPayRes(String paymentId, String status) {}

@Service class SynthPayRepo {
    Map<String,SynthPayRes> db = new ConcurrentHashMap<>();
    SynthPayRes save(SynthPayReq r) { String id="PAY-S-"+System.nanoTime(); SynthPayRes p=new SynthPayRes(id,"CAPTURED"); db.put(id,p); return p; }
    Optional<SynthPayRes> find(String id) { return Optional.ofNullable(db.get(id)); }
}
@GrpcGlobalServerInterceptor
class SynthLogger implements ServerInterceptor {
    AtomicInteger calls=new AtomicInteger();
    @Override public <Q,R> ServerCall.Listener<Q> interceptCall(ServerCall<Q,R> c, Metadata h, ServerCallHandler<Q,R> n) { calls.incrementAndGet(); return n.startCall(c,h); }
}
@GrpcService
class SynthPayGrpcSvc {
    private final SynthPayRepo repo;
    SynthPayGrpcSvc(SynthPayRepo r) { repo=r; }
    public void process(SynthPayReq req, StreamObserver<SynthPayRes> obs) {
        if(req.amount()<=0){obs.onError(Status.INVALID_ARGUMENT.withDescription("amount>0 required").asRuntimeException());return;}
        SynthPayRes r=repo.save(req); obs.onNext(r); obs.onCompleted();
    }
    public void get(String paymentId, StreamObserver<SynthPayRes> obs) {
        repo.find(paymentId).ifPresentOrElse(
            p->{obs.onNext(p);obs.onCompleted();},
            ()->obs.onError(Status.NOT_FOUND.withDescription(paymentId).asRuntimeException()));
    }
}

interface SynthTradeStub { String trade(String s); }
class SynthDeadlineClient {
    private final SynthTradeStub stub;
    SynthDeadlineClient(SynthTradeStub s){stub=s;}
    String call(String symbol){
        try{return stub.trade(symbol);}
        catch(StatusRuntimeException e){
            if(e.getStatus().getCode()==Status.Code.DEADLINE_EXCEEDED) return stub.trade(symbol+"-retry");
            throw new RuntimeException(e);
        }
    }
}

